#!/bin/bash
set -euo pipefail
BASE="http://127.0.0.1:8080"
COOKIE="/tmp/rd_g5_patch_cookie.txt"
JSON_FILE="/tmp/grade5_image_questions_patch2.json"

before=$(mysql -uroot -pJatni@752050 robodynamics_db -Nse "SELECT COUNT(*) FROM rd_quiz_questions WHERE course_session_id=1085;")
echo "BEFORE_COUNT=$before"

cat > /tmp/grade5_image_questions_patch2.b64 <<'B64'

B64
base64 -d /tmp/grade5_image_questions_patch2.b64 > "$JSON_FILE"

rm -f "$COOKIE"
curl -s -c "$COOKIE" -b "$COOKIE" -o /tmp/rd_g5_patch_login.txt -w "LOGIN_HTTP=%{http_code}\n"   -d "userName=anirudh&password=anirudh" "$BASE/login"

curl -s -b "$COOKIE" -o /tmp/rd_g5_patch_resp.json -w "UPLOAD_HTTP=%{http_code}\n"   -F "courseId=34"   -F "sessionId=1085"   -F "file=@$JSON_FILE;type=application/json"   "$BASE/exam-prep/api/upload-question-bank"

echo "UPLOAD_RESPONSE_BEGIN"
cat /tmp/rd_g5_patch_resp.json
echo
echo "UPLOAD_RESPONSE_END"

after=$(mysql -uroot -pJatni@752050 robodynamics_db -Nse "SELECT COUNT(*) FROM rd_quiz_questions WHERE course_session_id=1085;")
echo "AFTER_COUNT=$after"
